SELECT course_id, average_grade, pass_rate
FROM course_reports
ORDER BY average_grade DESC;

SELECT AVG(total_students) AS average_students
FROM departments
WHERE established_year > 2000;

SELECT AVG(enrollments_count) AS average_students_per_course
FROM (
  SELECT course_id, COUNT(*) AS enrollments_count
  FROM enrollments
  GROUP BY course_id
) AS enrollments_summary;

SELECT average_grade
FROM course_reports
ORDER BY average_grade DESC;
